public async Task<PurchaseResult> PurchaseTicketsAsync(int eventId, int userId, int quantity)
{
    if (quantity <= 0)
    {
        return new PurchaseResult(false, "Quantity must be positive.");
    }

    await _ticketPurchaseSemaphore.WaitAsync();
    try
    {
        using (var context = new YourDbContext()) // Replace YourDbContext with your actual DbContext
        {
            // Use a transaction for atomicity
            using (var transaction = await context.Database.BeginTransactionAsync())
            {
                try
                {
                    // Lock the event row for update to prevent race conditions on seat count
                    // For SQL Server, this might involve a "WITH (UPDLOCK, ROWLOCK)" hint
                    // EF Core doesn't directly expose table hints in a cross-database way for single entities.
                    // A common pattern is to select for update or use optimistic concurrency.
                    // For high concurrency, a raw SQL query might be more explicit for locking.
                    // Example using EF Core's optimistic concurrency (recommended for scalability):
                    var eventToUpdate = await context.Events
                                                    .Where(e => e.Id == eventId)
                                                    .FirstOrDefaultAsync();

                    if (eventToUpdate == null)
                    {
                        await transaction.RollbackAsync();
                        return new PurchaseResult(false, "Event not found.");
                    }

                    // Check available seats
                    if (eventToUpdate.AvailableSeats < quantity)
                    {
                        await transaction.RollbackAsync();
                        return new PurchaseResult(false, $"Not enough seats available. Only {eventToUpdate.AvailableSeats} left.");
                    }

                    // Update inventory
                    eventToUpdate.AvailableSeats -= quantity;

                    // Add a new ticket purchase record
                    var purchase = new TicketPurchase
                    {
                        EventId = eventId,
                        UserId = userId,
                        Quantity = quantity,
                        PurchaseDate = DateTime.UtcNow
                    };
                    context.TicketPurchases.Add(purchase);

                    // Save changes. If optimistic concurrency token is used, this will throw DbUpdateConcurrencyException
                    // if another transaction modified the eventToUpdate.AvailableSeats or its concurrency token.
                    await context.SaveChangesAsync();

                    await transaction.CommitAsync();
                    return new PurchaseResult(true, "Tickets purchased successfully.");
                }
                catch (DbUpdateConcurrencyException ex)
                {
                    // Handle concurrency conflict: another user updated the event simultaneously
                    await transaction.RollbackAsync();
                    // Log the exception details for debugging
                    Console.WriteLine($"Concurrency conflict during ticket purchase: {ex.Message}");
                    return new PurchaseResult(false, "A concurrency conflict occurred. Please try again.");
                }
                catch (Exception ex)
                {
                    await transaction.RollbackAsync();
                    // Log the exception
                    Console.WriteLine($"Error during ticket purchase: {ex.Message}");
                    return new PurchaseResult(false, "An unexpected error occurred during purchase.");
                }
            }
        }
    }
    finally
